<?php
 namespace League\CommonMark\Block\Parser; use League\CommonMark\Block\Element\FencedCode; use League\CommonMark\ContextInterface; use League\CommonMark\Cursor; final class FencedCodeParser implements BlockParserInterface { public function parse(ContextInterface $context, Cursor $cursor): bool { if ($cursor->isIndented()) { return false; } $c = $cursor->getCharacter(); if ($c !== ' ' && $c !== "\t" && $c !== '`' && $c !== '~') { return false; } $indent = $cursor->getIndent(); $fence = $cursor->match('/^[ \t]*(?:`{3,}(?!.*`)|~{3,})/'); if ($fence === null) { return false; } $fence = \ltrim($fence, " \t"); $fenceLength = \strlen($fence); $context->addBlock(new FencedCode($fenceLength, $fence[0], $indent)); return true; } } 